local xml = require "xml"
local cjson = require "cjson"

-- Parse XML from request body
local function parse_xml_request()
    local body = ngx.req.get_body_data()
    if not body then
        ngx.status = 400
        ngx.say("Missing request body")
        ngx.exit(400)
        return
    end
    
    -- Parse XML with entity reference support
    local parser = xml.new_parser()
    parser:set_option("XML_PARSE_NOENT", true)  -- Enable entity reference parsing
    
    local doc, err = parser:parse(body)
    if not doc then
        ngx.status = 400
        ngx.say("Invalid XML: " .. err)
        ngx.exit(400)
        return
    end
    
    return doc
end

-- Extract data from parsed XML
local function extract_data(doc)
    local data = {}
    
    -- Get root element
    local root = doc:get_root_element()
    if not root then
        return nil
    end
    
    -- Extract all child elements
    local children = root:get_children()
    for i, child in ipairs(children) do
        local name = child:get_name()
        local value = child:get_text()
        
        -- Handle nested elements
        local sub_children = child:get_children()
        if #sub_children > 0 then
            data[name] = {}
            for j, sub_child in ipairs(sub_children) do
                data[name][sub_child:get_name()] = sub_child:get_text()
            end
        else
            data[name] = value
        end
    end
    
    return data
end

-- Main handler
local function handle_soap_request()
    local doc = parse_xml_request()
    if not doc then
        return
    end
    
    local extracted_data = extract_data(doc)
    if not extracted_data then
        ngx.status = 400
        ngx.say("Failed to extract data from XML")
        ngx.exit(400)
        return
    end
    
    -- Process extracted data
    -- Your processing logic here
    
    -- Return processed data as JSON
    ngx.header.content_type = "application/json"
    ngx.say(cjson.encode(extracted_data))
end

-- Execute handler
handle_soap_request()